// CMS status codes → label + color
function resolveStatus(code) {
    if (code <= 100) return {
        label: "Waiting",
        color: "text-warning bg-warning-bg border-warning-border"
    };
    if (code < 300) return {
        label: "In Progress",
        color: "text-info bg-info-bg border-info-border"
    };
    if (code < 500) return {
        label: "Done",
        color: "text-success bg-success-bg border-success-border"
    };
    if (code === 900) return {
        label: "Exited",
        color: "text-muted-foreground bg-muted border-border"
    };
    return {
        label: "Complete",
        color: "text-success bg-success-bg border-success-border"
    };
}
